1179                     << "      LHS:" << *CmpIndVar << '\n'
1180                     << "       op:\t" << (P == ICmpInst::ICMP_NE ? "!=" : "==")
1181                     << "\n"
1182                     << "      RHS:\t" << *ExitCnt << "\n"
1183                     << "ExitCount:\t" << *ExitCount << "\n"
1184                     << "  was: " << *BI->getCondition() << "\n");
